    43→     *
    44→     * @param offset The offset to be committed
    45→     * @param leaderEpoch Optional leader epoch of the last consumed record
    46→     * @param metadata Non-null metadata
    47→     */
    48→    public OffsetAndMetadata(long offset, Optional<Integer> leaderEpoch, String metadata) {
    49→        if (offset < 0)
    50→            throw new IllegalArgumentException("Invalid negative offset");
    51→
    52→        this.offset = offset;
    53→        this.leaderEpoch = leaderEpoch.orElse(null);
    54→
    55→        // The server converts null metadata to an empty string. So we store it as an empty string as well on the client
    56→        // to be consistent.
    57→        if (metadata == null)
    58→            this.metadata = OffsetFetchResponse.NO_METADATA;
    59→        else
    60→            this.metadata = metadata;
    61→    }
    62→
    63→    /**
    64→     * Construct a new OffsetAndMetadata object for committing through {@link KafkaConsumer}.
    65→     * @param offset The offset to be committed
    66→     * @param metadata Non-null metadata
