    56→/**
    57→ * An abstract implementation of {@link SourceReader} which provides some synchronization between
    58→ * the mail box main thread and the SourceReader internal threads. This class allows user to just
    59→ * provide a {@link SplitReader} and snapshot the split state.
    60→ *
    61→ * <p>This implementation provides the following metrics out of the box:
    62→ *
    63→ * <ul>
    64→ *   <li>{@link OperatorIOMetricGroup#getNumRecordsInCounter()}
    65→ * </ul>
    66→ *
    67→ * @param <E> The rich element type that contains information for split state update or timestamp
    68→ *     extraction.
    69→ * @param <T> The final element type to emit.
    70→ * @param <SplitT> the immutable split type.
    71→ * @param <SplitStateT> the mutable type of split state.
    72→ */
    73→@PublicEvolving
    74→public abstract class SourceReaderBase<E, T, SplitT extends SourceSplit, SplitStateT>
    75→        implements SourceReader<T, SplitT> {
    76→    private static final Logger LOG = LoggerFactory.getLogger(SourceReaderBase.class);
    77→
    78→    /** A queue to buffer the elements fetched by the fetcher thread. */
    79→    private final FutureCompletingBlockingQueue<RecordsWithSplitIds<E>> elementsQueue;
    80→
    81→    /** The state of the splits. */
    82→    private final Map<String, SplitContext<T, SplitStateT>> splitStates;
    83→
    84→    /** The record emitter to handle the records read by the SplitReaders. */
    85→    protected final RecordEmitter<E, T, SplitStateT> recordEmitter;
    86→
    87→    /** The split fetcher manager to run split fetchers. */
    88→    protected final SplitFetcherManager<E, SplitT> splitFetcherManager;
    89→
    90→    /** The configuration for the reader. */
    91→    protected final SourceReaderOptions options;
    92→
    93→    /** The raw configurations that may be used by subclasses. */
    94→    protected final Configuration config;
    95→
    96→    private final Counter numRecordsInCounter;
    97→
    98→    /** The context of this source reader. */
    99→    protected SourceReaderContext context;
   100→
   101→    /** The latest fetched batch of records-by-split from the split reader. */
   102→    @Nullable private RecordsWithSplitIds<E> currentFetch;
   103→
   104→    @Nullable private SplitContext<T, SplitStateT> currentSplitContext;
   105→    @Nullable private SourceOutput<T> currentSplitOutput;
   106→
   107→    /** Indicating whether the SourceReader will be assigned more splits or not. */
   108→    private boolean noMoreSplitsAssignment;
   109→
   110→    @Nullable protected final RecordEvaluator<T> eofRecordEvaluator;
   111→
   112→    /** Indicating whether the SourceReader supports rate limiting or not. */
   113→    private final boolean rateLimitingEnabled;
   114→
   115→    /** The {@link RateLimiter} uses for rate limiting. */
   116→    @Nullable private final RateLimiter<SplitT> rateLimiter;
   117→
   118→    /** Future that tracks the result of acquiring permission from {@link #rateLimiter}. */
   119→    @Nullable private CompletableFuture<Void> rateLimitPermissionFuture;
