   176→    @Override
   177→    public InputStatus pollNext(ReaderOutput<T> output) throws Exception {
   178→        // make sure we have a fetch we are working on, or move to the next
   179→        RecordsWithSplitIds<E> recordsWithSplitId = this.currentFetch;
   180→        if (recordsWithSplitId == null) {
   181→            recordsWithSplitId = getNextFetch(output);
   182→            if (recordsWithSplitId == null) {
   183→                return trace(finishedOrAvailableLater());
   184→            }
   185→        }
   186→        if (rateLimitingEnabled) {
   187→            return pollNextWithRateLimiting(recordsWithSplitId, output);
   188→        } else {
   189→            return pollNextWithoutRateLimiting(recordsWithSplitId, output);
   190→        }
   191→    }
   192→
   193→    private InputStatus pollNextWithoutRateLimiting(
   194→            RecordsWithSplitIds<E> recordsWithSplitId, ReaderOutput<T> output) throws Exception {
   195→        // we need to loop here, in case we may have to go across splits
   196→        while (true) {
   197→            // Process one record.
   198→            final E record = recordsWithSplitId.nextRecordFromSplit();
   199→            if (record != null) {
   200→                // emit the record.
   201→                numRecordsInCounter.inc(1);
   202→                recordEmitter.emitRecord(record, currentSplitOutput, currentSplitContext.state);
   203→                LOG.trace("Emitted record: {}", record);
   204→                // We always emit MORE_AVAILABLE here, even though we do not strictly know whether
   205→                // more is available. If nothing more is available, the next invocation will find
   206→                // this out and return the correct status.
   207→                // That means we emit the occasional 'false positive' for availability, but this
   208→                // saves us doing checks for every record. Ultimately, this is cheaper.
   209→                return trace(InputStatus.MORE_AVAILABLE);
   210→            } else if (!moveToNextSplit(recordsWithSplitId, output)) {
   211→                // The fetch is done and we just discovered that and have not emitted anything, yet.
   212→                // We need to move to the next fetch. As a shortcut, we call pollNext() here again,
   213→                // rather than emitting nothing and waiting for the caller to call us again.
   214→                return pollNext(output);
   215→            }
   216→        }
   217→    }
   218→
   219→    private InputStatus pollNextWithRateLimiting(
   220→            RecordsWithSplitIds<E> recordsWithSplitId, ReaderOutput<T> output) throws Exception {
   221→        // make sure we have a fetch we are working on, or move to the next
   222→        while (true) {
   223→            // Check if the previous record count reached the limit of rateLimiter.
   224→            if (!rateLimitPermissionFuture.isDone()) {
   225→                return trace(InputStatus.MORE_AVAILABLE);
   226→            }
   227→            // Process one record.
   228→            final E record = recordsWithSplitId.nextRecordFromSplit();
   229→            if (record != null) {
   230→                // emit the record.
   231→                numRecordsInCounter.inc(1);
   232→                recordEmitter.emitRecord(record, currentSplitOutput, currentSplitContext.state);
   233→                LOG.trace("Emitted record: {}", record);
   234→                RateLimitingSourceOutputWrapper<T> rateLimitingSourceOutputWrapper =
   235→                        (RateLimitingSourceOutputWrapper<T>) currentSplitOutput;
   236→                if (rateLimitingSourceOutputWrapper.getRecordsOfCurrentWindow() > 0) {
   237→                    // Acquire permit from rateLimiter.
   238→                    rateLimitPermissionFuture =
   239→                            rateLimiter
   240→                                    .acquire(
   241→                                            rateLimitingSourceOutputWrapper
   242→                                                    .getRecordsOfCurrentWindow())
   243→                                    .toCompletableFuture();
   244→                }
   245→                rateLimitingSourceOutputWrapper.resetWindowRecordCount();
   246→
   247→                // We always emit MORE_AVAILABLE here, even though we do not strictly know whether
   248→                // more is available. If nothing more is available, the next invocation will find
   249→                // this out and return the correct status.
   250→                // That means we emit the occasional 'false positive' for availability, but this
   251→                // saves us doing checks for every record. Ultimately, this is cheaper.
   252→                return trace(InputStatus.MORE_AVAILABLE);
   253→            } else if (!moveToNextSplit(recordsWithSplitId, output)) {
   254→                // The fetch is done and we just discovered that and have not emitted anything, yet.
   255→                // We need to move to the next fetch. As a shortcut, we call pollNext() here again,
   256→                // rather than emitting nothing and waiting for the caller to call us again.
   257→                return pollNext(output);
   258→            }
   259→        }
   260→    }
   261→
   262→    private InputStatus trace(InputStatus status) {
   263→        LOG.trace("Source reader status: {}", status);
   264→        return status;
   265→    }
   266→
   267→    @Nullable
   268→    private RecordsWithSplitIds<E> getNextFetch(final ReaderOutput<T> output) {
   269→        splitFetcherManager.checkErrors();
   270→
   271→        LOG.trace("Getting next source data batch from queue");
   272→        final RecordsWithSplitIds<E> recordsWithSplitId = elementsQueue.poll();
   273→        if (recordsWithSplitId == null || !moveToNextSplit(recordsWithSplitId, output)) {
   274→            // No element available, set to available later if needed.
   275→            return null;
   276→        }
   277→
   278→        currentFetch = recordsWithSplitId;
   279→        return recordsWithSplitId;
   280→    }
   281→
   282→    private void finishCurrentFetch(
   283→            final RecordsWithSplitIds<E> fetch, final ReaderOutput<T> output) {
   284→        currentFetch = null;
   285→        currentSplitContext = null;
   286→        currentSplitOutput = null;
   287→
   288→        final Set<String> finishedSplits = fetch.finishedSplits();
   289→        if (!finishedSplits.isEmpty()) {
   290→            LOG.info("Finished reading split(s) {}", finishedSplits);
   291→            Map<String, SplitStateT> stateOfFinishedSplits = new HashMap<>();
   292→            for (String finishedSplitId : finishedSplits) {
   293→                stateOfFinishedSplits.put(
   294→                        finishedSplitId, splitStates.remove(finishedSplitId).state);
   295→                output.releaseOutputForSplit(finishedSplitId);
   296→            }
   297→            onSplitFinished(stateOfFinishedSplits);
   298→        }
   299→
   300→        fetch.recycle();
   301→    }
   302→
   303→    private boolean moveToNextSplit(
   304→            RecordsWithSplitIds<E> recordsWithSplitIds, ReaderOutput<T> output) {
   305→        final String nextSplitId = recordsWithSplitIds.nextSplit();
   306→        if (nextSplitId == null) {
   307→            LOG.trace("Current fetch is finished.");
   308→            finishCurrentFetch(recordsWithSplitIds, output);
   309→            return false;
   310→        }
   311→
   312→        currentSplitContext = splitStates.get(nextSplitId);
   313→        checkState(currentSplitContext != null, "Have records for a split that was not registered");
   314→
   315→        Function<T, Boolean> eofRecordHandler = null;
   316→        if (eofRecordEvaluator != null) {
   317→            eofRecordHandler =
   318→                    record -> {
   319→                        if (!eofRecordEvaluator.isEndOfStream(record)) {
   320→                            return false;
   321→                        }
   322→                        SplitT split =
   323→                                toSplitType(currentSplitContext.splitId, currentSplitContext.state);
   324→                        splitFetcherManager.removeSplits(Collections.singletonList(split));
   325→                        return true;
   326→                    };
   327→        }
   328→        if (rateLimitingEnabled) {
   329→            rateLimiter.notifyAddingSplit(
   330→                    this.toSplitType(
   331→                            this.currentSplitContext.splitId, this.currentSplitContext.state));
   332→        }
   333→        currentSplitOutput =
   334→                currentSplitContext.getOrCreateSplitOutput(
   335→                        output, eofRecordHandler, rateLimitingEnabled);
   336→        LOG.trace("Emitting records from fetch for split {}", nextSplitId);
   337→        return true;
   338→    }
